class CookieConsent{constructor(){this.cookieName="consent_status",this.cookieExpiry=365,this.initializeBanner(),this.initializeModal(),this.checkCookieConsent()}initializeBanner(){document.body.insertAdjacentHTML("beforeend",'\n            <div class="cookie-banner" id="cookieBanner">\n                <div class="cookie-banner__content">\n                    <div class="cookie-banner__text">\n                        <h3>Cookie-instellingen</h3>\n                        <p>Wij gebruiken cookies om uw ervaring te verbeteren en onze website te optimaliseren. U kunt kiezen welke cookies u wilt accepteren. Lees meer in ons <a href="/cookiebeleid.html">cookiebeleid</a>.</p>\n                    </div>\n                    <div class="cookie-banner__actions">\n                        <button class="cookie-banner__button cookie-banner__button--accept" id="acceptAllCookies">Alle cookies accepteren</button>\n                        <button class="cookie-banner__button cookie-banner__button--settings" id="openCookieSettings">Cookie-instellingen</button>\n                    </div>\n                </div>\n            </div>\n        '),document.getElementById("acceptAllCookies").addEventListener("click",(()=>this.acceptAllCookies())),document.getElementById("openCookieSettings").addEventListener("click",(()=>this.openSettings()))}initializeModal(){document.body.insertAdjacentHTML("beforeend",'\n            <div class="cookie-settings-modal" id="cookieSettingsModal">\n                <div class="cookie-settings-modal__content">\n                    <div class="cookie-settings-modal__header">\n                        <h3>Cookie-instellingen</h3>\n                        <button class="cookie-settings-modal__close" id="closeCookieSettings">&times;</button>\n                    </div>\n                    <div class="cookie-settings-modal__options">\n                        <div class="cookie-option">\n                            <div class="cookie-option__info">\n                                <h4 class="cookie-option__title">Noodzakelijke cookies</h4>\n                                <p class="cookie-option__description">Deze cookies zijn essentieel voor het functioneren van de website. Ze onthouden bijvoorbeeld uw taalvoorkeuren en of u bent ingelogd.</p>\n                            </div>\n                            <label class="cookie-option__toggle">\n                                <input type="checkbox" checked disabled>\n                                <span class="cookie-option__toggle-slider"></span>\n                            </label>\n                        </div>\n                        <div class="cookie-option">\n                            <div class="cookie-option__info">\n                                <h4 class="cookie-option__title">Analytische cookies</h4>\n                                <p class="cookie-option__description">We gebruiken analytische cookies om te begrijpen hoe bezoekers onze website gebruiken. Deze informatie helpt ons de website te verbeteren.</p>\n                            </div>\n                            <label class="cookie-option__toggle">\n                                <input type="checkbox" id="analyticsCookies">\n                                <span class="cookie-option__toggle-slider"></span>\n                            </label>\n                        </div>\n                        <div class="cookie-option">\n                            <div class="cookie-option__info">\n                                <h4 class="cookie-option__title">Functionele cookies</h4>\n                                <p class="cookie-option__description">Deze cookies onthouden uw voorkeuren en helpen bij het personaliseren van uw websitebezoek.</p>\n                            </div>\n                            <label class="cookie-option__toggle">\n                                <input type="checkbox" id="functionalCookies">\n                                <span class="cookie-option__toggle-slider"></span>\n                            </label>\n                        </div>\n                    </div>\n                    <div class="cookie-settings-modal__actions">\n                        <button class="cookie-banner__button cookie-banner__button--settings" id="saveCookieSettings">Instellingen opslaan</button>\n                    </div>\n                </div>\n            </div>\n        '),document.getElementById("closeCookieSettings").addEventListener("click",(()=>this.closeSettings())),document.getElementById("saveCookieSettings").addEventListener("click",(()=>this.saveSettings())),document.getElementById("cookieSettingsModal").addEventListener("click",(e=>{"cookieSettingsModal"===e.target.id&&this.closeSettings()}));const e=this.getCookie(this.cookieName);if(e){const o=JSON.parse(e);document.getElementById("analyticsCookies").checked=o.analytics,document.getElementById("functionalCookies").checked=o.functional}}checkCookieConsent(){this.getCookie(this.cookieName)||document.getElementById("cookieBanner").classList.add("visible")}acceptAllCookies(){const e={necessary:!0,analytics:!0,functional:!0};this.setConsent(e),this.hideBanner(),this.applyPreferences(e)}openSettings(){document.getElementById("cookieSettingsModal").classList.add("visible")}closeSettings(){document.getElementById("cookieSettingsModal").classList.remove("visible")}saveSettings(){const e={necessary:!0,analytics:document.getElementById("analyticsCookies").checked,functional:document.getElementById("functionalCookies").checked};this.setConsent(e),this.closeSettings(),this.hideBanner(),this.applyPreferences(e)}setConsent(e){this.setCookie(this.cookieName,JSON.stringify(e),this.cookieExpiry)}hideBanner(){document.getElementById("cookieBanner").classList.remove("visible")}applyPreferences(e){var o,n,t,i,s,c;e.analytics?"undefined"==typeof ga&&(o=window,n=document,t="script",i="ga",o.GoogleAnalyticsObject=i,o[i]=o[i]||function(){(o[i].q=o[i].q||[]).push(arguments)},o[i].l=1*new Date,s=n.createElement(t),c=n.getElementsByTagName(t)[0],s.async=1,s.src="https://www.google-analytics.com/analytics.js",c.parentNode.insertBefore(s,c),ga("create","UA-XXXXX-Y","auto"),ga("send","pageview")):(this.deleteCookie("_ga"),this.deleteCookie("_gid")),e.functional||this.deleteCookie("language_pref")}setCookie(e,o,n){const t=new Date;t.setTime(t.getTime()+24*n*60*60*1e3);const i="; expires="+t.toUTCString();document.cookie=e+"="+(o||"")+i+"; path=/; SameSite=Lax"}getCookie(e){const o=e+"=",n=document.cookie.split(";");for(let e=0;e<n.length;e++){let t=n[e];for(;" "===t.charAt(0);)t=t.substring(1,t.length);if(0===t.indexOf(o))return t.substring(o.length,t.length)}return null}deleteCookie(e){document.cookie=e+"=; Path=/; Expires=Thu, 01 Jan 1970 00:00:01 GMT;"}}document.addEventListener("DOMContentLoaded",(()=>{new CookieConsent}));